import PDFDocument from 'pdfkit';
import { Buffer } from 'buffer';

export interface ReportData {
  claim: any;
  claimant: any;
  trinityCheck: any;
  documents: any[];
  tenant?: any;
}

export class TrinityReportGenerator {
  private readonly primaryColor = '#0B744E';
  private readonly secondaryColor = '#4A5568';
  private readonly borderColor = '#CBD5E0';
  private readonly lightBg = '#F7FAFC';

  // Base64 logo string read from file
  private readonly logoBase64: string;

  constructor() {
    this.logoBase64 =
      '';
  }

  async generate(data: ReportData): Promise<Buffer> {
    return new Promise((resolve, reject) => {
      const doc = new PDFDocument({
        margin: 40,
        size: 'A4',
        bufferPages: true,
      });

      const chunks: Buffer[] = [];
      doc.on('data', chunk => chunks.push(chunk));
      doc.on('end', () => resolve(Buffer.concat(chunks)));
      doc.on('error', reject);

      // Set bottom margin to reserve space for footer
      // This ensures auto-wrapped text respects the disclaimer section
      const reserve = this.footerReserve(doc);
      doc.page.margins.bottom = reserve;

      // Automatically add header to every new page
      doc.on('pageAdded', () => {
        this.generateHeader(doc, data);
      });

      // Initial header for the first page
      this.generateHeader(doc, data);

      // 0 : OVERVIEW (NEW)
      this.generateOverviewSection(doc, data);

      // A : SNAPSHOT
      this.generateSnapshotSection(doc, data);

      // B : TRINITY VERIFICATION
      this.generateTrinityVerificationSection(doc, data);

      // C : EXTRACTED DATA SECTIONS
      this.generateExtractedDataSections(doc, data);

      // D : INTELLIGENCE ANALYSIS
      this.generateIntelligenceSection(doc, data);

      this.generateFooter(doc);

      doc.end();
    });
  }

  // ─── Footer / page-geometry helpers ────────────────────────────────────────

  /**
   * Height (pts) that must be reserved at the bottom of every page for the
   * disclaimer box + page-number line.  Computed once so it is always the
   * source-of-truth used by both `generateFooter` and page-overflow guards.
   */
  private footerReserve(doc: PDFKit.PDFDocument): number {
    const disclaimer =
      'DISCLAIMER: This report is generated by the True Claim Insight (TCI) Intelligence Engine using extracted document data and cross-verification algorithms. It is provided as a decision-support tool for loss adjusters and should be used in conjunction with professional judgment. TCI does not assume liability for decisions made based solely on this automated output.';
    const disclaimerBoxWidth = 515;
    const disclaimerTextWidth = disclaimerBoxWidth - 20;
    doc.fontSize(6).font('Helvetica');
    const textH = doc.heightOfString(disclaimer, { width: disclaimerTextWidth, align: 'justify' });

    const topGap = 20; // safe clearance between last body content and disclaimer box
    const boxPadding = 14; // inner vertical padding inside the disclaimer box (top+bottom)
    const boxH = textH + boxPadding;
    const gap = 8; // gap between bottom of disclaimer box and page-number line
    const pageNumH = 18; // height of the page-number text line
    const bottomMargin = 24; // breathing room below the page-number line
    const safetyBuffer = 12; // extra buffer to account for font metric rounding

    return topGap + boxH + gap + pageNumH + bottomMargin + safetyBuffer;
  }

  /**
   * The lowest Y position at which new content may safely start on `doc`'s
   * current page (i.e. anything below this Y will collide with the footer).
   */
  private contentBottom(doc: PDFKit.PDFDocument): number {
    return doc.page.height - this.footerReserve(doc);
  }

  /**
   * If the current cursor + `neededPts` would overflow the usable area, add a
   * new page and re-draw the header, then reset `doc.y` to content start.
   */
  private ensureSpace(
    doc: PDFKit.PDFDocument,
    data: ReportData | { claim: { claimNumber: string } },
    neededPts = 20
  ): void {
    if (doc.y + neededPts > this.contentBottom(doc)) {
      doc.addPage();
    }
  }

  // ─── Date / string formatters ─────────────────────────────────────────────

  private formatDate(date: any): string {
    if (!date) return 'N/A';
    try {
      const d = new Date(date);
      if (isNaN(d.getTime())) return String(date);
      return d.toISOString().split('T')[0];
    } catch {
      return 'N/A';
    }
  }

  private formatTitleCase(str: string) {
    if (!str) return '';
    return str
      .split('_')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(' ');
  }

  private sanitizeString(str: any): string {
    if (str === null || str === undefined) return '';
    const text = String(str);
    // Map Cyrillic homoglyphs to Latin equivalents
    const homoglyphMap: Record<string, string> = {
      А: 'A',
      В: 'B',
      Е: 'E',
      К: 'K',
      М: 'M',
      Н: 'N',
      О: 'O',
      Р: 'P',
      С: 'C',
      Т: 'T',
      Х: 'X',
      а: 'a',
      е: 'e',
      о: 'o',
      р: 'p',
      с: 'c',
      у: 'y',
      х: 'x',
      І: 'I',
      і: 'i',
      Ј: 'J',
      ј: 'j',
      Ѕ: 'S',
      ѕ: 's',
    };
    // Replace characters outside basic Latin range if they are known homoglyphs
    return text
      .replace(/[А-яЁёІіЈјЅѕ]/g, char => homoglyphMap[char] || char)
      .replace(/[^\x00-\x7F]/g, ''); // Remove remaining non-ASCII to prevent PDF garbage
  }

  private generateHeader(doc: PDFKit.PDFDocument, data: ReportData) {
    const leftX = 40;
    const rightX = 320;
    const topY = 35;
    const logoWidth = 36;
    const logoHeight = 36;

    try {
      if (this.logoBase64) {
        const logoBuffer = Buffer.from(this.logoBase64, 'base64');
        doc.image(logoBuffer, leftX, topY, { width: logoWidth, height: logoHeight });
      }
    } catch (e) {}

    // Vertically centred beside the logo
    const titleX = leftX + logoWidth + 10;
    const titleY = topY + (logoHeight - 8) / 2;
    doc
      .fontSize(16)
      .font('Helvetica-Bold')
      .fillColor('#000000')
      .text('TCI REPORT', titleX, titleY, { lineBreak: false });

    doc
      .fontSize(7)
      .font('Helvetica')
      .fillColor(this.secondaryColor)
      .text(`Report Date: ${this.formatDate(new Date())}`, rightX, topY + 10, {
        align: 'right',
        width: 235,
      });

    doc
      .fontSize(7)
      .font('Helvetica')
      .fillColor(this.secondaryColor)
      .text(`CONFIDENTIAL - ${data.claim.claimNumber}`, rightX, topY + 20, {
        align: 'right',
        width: 235,
      });

    doc.moveTo(40, 80).lineTo(555, 80).stroke(this.primaryColor);
    doc.y = 90;
  }

  private generateOverviewSection(doc: PDFKit.PDFDocument, data: ReportData) {
    const startY = doc.y + 10;
    const boxWidth = 515;
    const boxHeight = 100;

    // Trust Score Gauge
    this.drawGauge(
      doc,
      40,
      startY,
      boxWidth,
      boxHeight,
      'TRUST SCORE',
      data.trinityCheck.score || 0,
      '%',
      data.trinityCheck.status
    );

    doc.y = startY + boxHeight + 10;
  }

  private drawGauge(
    doc: PDFKit.PDFDocument,
    x: number,
    y: number,
    w: number,
    h: number,
    title: string,
    value: number,
    unit: string,
    statusWording?: string
  ) {
    doc.rect(x, y, w, h).stroke(this.borderColor);
    doc
      .fillColor(this.secondaryColor)
      .fontSize(8)
      .font('Helvetica-Bold')
      .text(title, x + 10, y + 8);

    const centerX = x + w / 2;
    const centerY = y + h - 25;
    const radius = 45;

    // Draw Arc
    doc.lineWidth(10);
    doc.lineCap('butt');
    doc
      .moveTo(centerX - radius, centerY)
      .path(
        `M ${centerX - radius} ${centerY} A ${radius} ${radius} 0 0 1 ${centerX + radius} ${centerY}`
      )
      .stroke('#E2E8F0');

    // Draw Value Arc
    const angle = (value / 100) * Math.PI;
    const color = value > 70 ? this.primaryColor : value > 40 ? '#B7791F' : '#C53030';
    doc.stroke(color);
    doc
      .moveTo(centerX - radius, centerY)
      .path(
        `M ${centerX - radius} ${centerY} A ${radius} ${radius} 0 0 1 ${centerX - radius * Math.cos(angle)} ${centerY - radius * Math.sin(angle)}`
      )
      .stroke();

    // Needle
    const needlePadding = 12;
    doc.lineWidth(2).strokeOpacity(0.5);
    doc
      .moveTo(centerX, centerY)
      .lineTo(
        centerX - (radius - needlePadding) * Math.cos(angle),
        centerY - (radius - needlePadding) * Math.sin(angle)
      )
      .stroke('#4A5568');
    doc.circle(centerX, centerY, 3);
    doc.fillOpacity(1).fill('#4A5568');
    doc.strokeOpacity(1).fillOpacity(1);

    // Value percentage text (slightly below the needle pivot)
    doc
      .fillColor('#000000')
      .fontSize(14)
      .font('Helvetica-Bold')
      .text(`${value}${unit}`, x, centerY - 15, { width: w, align: 'center' });

    // Status wording below gauge
    if (statusWording) {
      const statusColor =
        statusWording.toUpperCase() === 'PASS'
          ? this.primaryColor
          : statusWording.toUpperCase() === 'FAIL'
            ? '#C53030'
            : '#B7791F';
      doc
        .fillColor(statusColor)
        .fontSize(10)
        .font('Helvetica-Bold')
        .text(statusWording.toUpperCase(), x, centerY + 12, { width: w, align: 'center' });
    }
  }

  private drawSectionHeader(
    doc: PDFKit.PDFDocument,
    letter: string,
    title: string,
    bubbleNum: string
  ) {
    const y = doc.y + 10;
    doc.rect(40, y, 515, 20).fill(this.primaryColor);

    doc.fillColor('#FFFFFF').fontSize(10).font('Helvetica-Bold');
    doc.text(`${letter} : ${title.toUpperCase()}`, 50, y + 6);

    // White Bubble
    const bubbleRadius = 7;
    const bubbleX = 540;
    const bubbleY = y + 10;
    doc.circle(bubbleX, bubbleY, bubbleRadius).fill('#FFFFFF');

    // Centered Number in Bubble
    doc.fillColor(this.primaryColor).fontSize(8).font('Helvetica-Bold');
    const textWidth = doc.widthOfString(bubbleNum);
    doc.text(bubbleNum, bubbleX - textWidth / 2, bubbleY - 3.5);

    doc.moveDown(1.5);
  }

  private generateSnapshotSection(doc: PDFKit.PDFDocument, data: ReportData) {
    this.drawSectionHeader(doc, 'A', 'Snapshot', '1');

    const tableData = [
      ['Claim Number', data.claim.claimNumber],
      ['Policy Number', data.claim.policyNumber],
      ['Claimant Name', data.claimant.fullName || 'N/A'],
      ['Claimant NRIC', data.claimant.nric || 'N/A'],
      ['Incident Date', this.formatDate(data.claim.incidentDate)],
      [
        'Incident Location',
        typeof data.claim.incidentLocation === 'object'
          ? data.claim.incidentLocation.address || 'N/A'
          : data.claim.incidentLocation,
      ],
      ['Vehicle Number', data.claim.vehiclePlateNumber || 'N/A'],
      [
        'Vehicle Make/Model',
        `${data.claim.vehicleMake} ${data.claim.vehicleModel}`.trim() || 'N/A',
      ],
      ['Trust Score', `${data.trinityCheck.score}%`],
      ['Verification Status', data.trinityCheck.status],
    ];

    this.drawSimpleTable(doc, tableData);
  }

  private drawSimpleTable(doc: PDFKit.PDFDocument, rows: string[][]) {
    const startX = 40;
    const col1Width = 150;
    const col2Width = 365;
    const rowHeight = 18;
    const contData = { claim: { claimNumber: 'CONT' } } as any;

    rows.forEach(row => {
      // Guard: ensure one row (+ a small look-ahead) fits before drawing
      this.ensureSpace(doc, contData, rowHeight + 4);

      const currentY = doc.y;
      const col1Val = this.sanitizeString(row[0]);
      const col2Val = this.sanitizeString(row[1]);

      // Draw backgrounds
      doc.rect(startX, currentY, col1Width, rowHeight).fill(this.lightBg);

      // Draw ONE outer border for the row to avoid double/thick lines
      doc.rect(startX, currentY, col1Width + col2Width, rowHeight).stroke(this.borderColor);
      // Draw ONE vertical separator
      doc
        .moveTo(startX + col1Width, currentY)
        .lineTo(startX + col1Width, currentY + rowHeight)
        .stroke(this.borderColor);

      doc
        .fillColor(this.secondaryColor)
        .fontSize(8)
        .font('Helvetica-Bold')
        .text(col1Val, startX + 10, currentY + 5, { lineBreak: false });
      doc
        .fillColor('#000000')
        .fontSize(8)
        .font('Helvetica')
        .text(col2Val, startX + col1Width + 10, currentY + 5, { width: col2Width - 20 });

      doc.y = currentY + rowHeight;
    });

    doc.moveDown(1);
  }

  private generateTrinityVerificationSection(doc: PDFKit.PDFDocument, data: ReportData) {
    // Need space for section header (30) + subtitle (14) + table header (20) + at least 1 row (20)
    this.ensureSpace(doc, data, 84);
    this.drawSectionHeader(doc, 'B', 'Trinity Verification', '2');

    doc
      .fillColor(this.secondaryColor)
      .fontSize(8)
      .font('Helvetica-Oblique')
      .text('Cross-checking extracted documents against claim declarations.', 40, doc.y - 4);
    doc.moveDown(0.5);

    const checks = data.trinityCheck.checkResults
      ? Object.values(data.trinityCheck.checkResults)
      : [];

    const startX = 40;
    const colWidths = [120, 275, 60, 60];

    // Draw the column-header row; if it won't fit, move to next page first
    this.ensureSpace(doc, data, 40);
    const yHeader = doc.y;
    doc.rect(startX, yHeader, 515, 20).fill(this.primaryColor);
    doc.fillColor('#FFFFFF').fontSize(8).font('Helvetica-Bold');
    doc.text('CHECK RULE', startX + 5, yHeader + 6);
    doc.text('FINDINGS', startX + colWidths[0] + 5, yHeader + 6);
    doc.text('STATUS', startX + colWidths[0] + colWidths[1] + 5, yHeader + 6);
    doc.text('CONF.', startX + colWidths[0] + colWidths[1] + colWidths[2] + 5, yHeader + 6);
    doc.y = yHeader + 20;

    checks.forEach((check: any) => {
      const textHeight = Math.max(
        20,
        doc.heightOfString(check.details || '', { width: colWidths[1] - 10 }) + 10
      );

      // If this row won't fit, add a page and re-draw the column headers
      if (doc.y + textHeight > this.contentBottom(doc)) {
        doc.addPage();
        const yH2 = doc.y;
        doc.rect(startX, yH2, 515, 20).fill(this.primaryColor);
        doc.fillColor('#FFFFFF').fontSize(8).font('Helvetica-Bold');
        doc.text('CHECK RULE', startX + 5, yH2 + 6);
        doc.text('FINDINGS', startX + colWidths[0] + 5, yH2 + 6);
        doc.text('STATUS', startX + colWidths[0] + colWidths[1] + 5, yH2 + 6);
        doc.text('CONF.', startX + colWidths[0] + colWidths[1] + colWidths[2] + 5, yH2 + 6);
        doc.y = yH2 + 20;
      }

      const y = doc.y;
      // Draw outer bounds for the row
      doc.rect(startX, y, 515, textHeight).stroke(this.borderColor);

      // Draw vertical separators
      let currentX = startX;
      for (let i = 0; i < colWidths.length - 1; i++) {
        currentX += colWidths[i];
        doc
          .moveTo(currentX, y)
          .lineTo(currentX, y + textHeight)
          .stroke(this.borderColor);
      }

      doc
        .fillColor('#000000')
        .fontSize(7)
        .font('Helvetica-Bold')
        .text(
          this.sanitizeString(this.formatTitleCase(check.check_id.split('_').slice(1).join('_'))),
          startX + 5,
          y + 5,
          { width: colWidths[0] - 10 }
        );
      doc
        .font('Helvetica')
        .text(this.sanitizeString(check.details || ''), startX + colWidths[0] + 5, y + 5, {
          width: colWidths[1] - 10,
        });

      const statusColor =
        check.is_pass === true ? '#0B744E' : check.is_pass === false ? '#C53030' : '#B7791F';
      doc
        .fillColor(statusColor)
        .font('Helvetica-Bold')
        .text(
          check.is_pass === true ? 'PASS' : check.is_pass === false ? 'FAIL' : 'WARN',
          startX + colWidths[0] + colWidths[1] + 5,
          y + 5
        );
      doc
        .fillColor('#000000')
        .font('Helvetica')
        .text(
          `${Math.round((check.confidence || 0) * 100)}%`,
          startX + colWidths[0] + colWidths[1] + colWidths[2] + 5,
          y + 5
        );

      doc.y = y + textHeight;
    });

    doc.moveDown(2);
  }

  private generateExtractedDataSections(doc: PDFKit.PDFDocument, data: ReportData) {
    if (!data.documents || data.documents.length === 0) return;

    // Always start extracted data on a fresh page
    // doc.addPage();
    this.drawSectionHeader(doc, 'C', 'Extracted Document Data', '3');

    let displayedCount = 0;
    data.documents.forEach(docItem => {
      const analysis = docItem.analysis;
      if (!analysis || !analysis.extractedData) return;

      displayedCount++;
      // Need at least enough room for a document title + one data row
      this.ensureSpace(doc, data, 46);

      doc
        .fillColor(this.primaryColor)
        .fontSize(10)
        .font('Helvetica-Bold')
        .text(`${displayedCount}. ${this.formatTitleCase(docItem.type)}`, 40);
      doc.moveDown(0.5);

      const extracted = analysis.extractedData as Record<string, any>;
      this.drawNestedData(doc, extracted, 0, data);
      doc.moveDown(2);
    });
  }

  private drawNestedData(doc: PDFKit.PDFDocument, data: any, level = 0, rootData?: ReportData) {
    const contData = rootData ?? ({ claim: { claimNumber: 'CONT' } } as any);
    const startX = 40;
    const availableWidth = 515;
    const col1Width = 180;
    const col2Width = availableWidth - col1Width;
    const textIndent = level * 15;

    if (typeof data !== 'object' || data === null) {
      this.ensureSpace(doc, contData, 14);
      const val = data === null || data === undefined || data === '' ? '-' : String(data);
      doc
        .fontSize(8)
        .font('Helvetica')
        .fillColor('#000000')
        .text(val, startX + textIndent);
      return;
    }

    const entries = Object.entries(data);

    entries.forEach(([key, value]) => {
      const formattedKey = this.sanitizeString(this.formatTitleCase(key));

      if (
        Array.isArray(value) &&
        value.length > 0 &&
        typeof value[0] === 'object' &&
        value[0] !== null
      ) {
        // Array of objects: draw header, then iterate with indices
        this.ensureSpace(doc, contData, 18);
        const parentY = doc.y;
        doc
          .rect(startX, parentY, availableWidth, 18)
          .fill('#E2E8F0')
          .rect(startX, parentY, availableWidth, 18)
          .stroke(this.borderColor)
          .fillColor(this.secondaryColor)
          .fontSize(8)
          .font('Helvetica-Bold')
          .text(formattedKey.toUpperCase(), startX + 5 + textIndent, parentY + 5, {
            width: availableWidth - 10 - textIndent,
          });
        doc.y = parentY + 18;

        value.forEach((item, idx) => {
          this.ensureSpace(doc, contData, 18);
          const itemY = doc.y;
          doc
            .rect(startX, itemY, availableWidth, 18)
            .fill('#E2E8F0')
            .rect(startX, itemY, availableWidth, 18)
            .stroke(this.borderColor)
            .fillColor(this.secondaryColor)
            .fontSize(8)
            .font('Helvetica-Bold')
            .text(`ITEM ${idx + 1}`, startX + 5 + textIndent, itemY + 5);
          doc.y = itemY + 18;
          this.drawNestedData(doc, item, level + 1, rootData);
        });
      } else if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
        // Nested object: shaded group header row, then recurse
        this.ensureSpace(doc, contData, 36);
        const rowStartY = doc.y;

        doc
          .rect(startX, rowStartY, availableWidth, 18)
          .fill('#E2E8F0')
          .rect(startX, rowStartY, availableWidth, 18)
          .stroke(this.borderColor)
          .fillColor(this.secondaryColor)
          .fontSize(8)
          .font('Helvetica-Bold')
          .text(formattedKey.toUpperCase(), startX + 5 + textIndent, rowStartY + 5, {
            width: availableWidth - 10 - textIndent,
            lineBreak: false,
          });
        doc.y = rowStartY + 18;
        this.drawNestedData(doc, value, level + 1, rootData);
      } else {
        // ── Leaf value: two-column key / value row ──────────────────────
        const rawValStr = Array.isArray(value)
          ? value.length === 0
            ? '-'
            : value.map(v => (typeof v === 'object' ? JSON.stringify(v) : String(v))).join(', ')
          : value === null || value === undefined || value === ''
            ? '-'
            : String(value);
        const valStr = this.sanitizeString(rawValStr);

        const isJustified = ['description'].includes(key.toLowerCase());
        const alignment = isJustified ? 'justify' : 'left';
        const rowHeight = Math.max(
          18,
          doc.heightOfString(valStr, { width: col2Width - 10, align: alignment }) + 10
        );

        // Guard: the entire row must fit; if not, new page
        this.ensureSpace(doc, contData, rowHeight);
        const rowStartY = doc.y;

        // Draw fills
        doc.rect(startX, rowStartY, col1Width, rowHeight).fill(this.lightBg);
        doc.rect(startX + col1Width, rowStartY, col2Width, rowHeight).fill('#FFFFFF');

        // Draw ONE outer border for the row
        doc.rect(startX, rowStartY, col1Width + col2Width, rowHeight).stroke(this.borderColor);
        // Draw ONE vertical separator
        doc
          .moveTo(startX + col1Width, rowStartY)
          .lineTo(startX + col1Width, rowStartY + rowHeight)
          .stroke(this.borderColor);

        // Key text
        doc
          .fillColor(this.secondaryColor)
          .fontSize(8)
          .font('Helvetica-Bold')
          .text(formattedKey, startX + 5 + textIndent, rowStartY + 5, {
            width: col1Width - 10 - textIndent,
            lineBreak: false,
          });

        // Value text – anchored to rowStartY so it always aligns with the key
        doc
          .fillColor('#000000')
          .fontSize(8)
          .font('Helvetica')
          .text(valStr, startX + col1Width + 5, rowStartY + 5, {
            width: col2Width - 10,
            align: alignment,
          });

        // Advance cursor past this row
        doc.y = rowStartY + rowHeight;
      }
    });
  }

  private generateIntelligenceSection(doc: PDFKit.PDFDocument, data: ReportData) {
    const sectionLetter = data.documents && data.documents.length > 0 ? 'D' : 'C';
    const bubbleIndex = data.documents && data.documents.length > 0 ? '4' : '3';

    // Need at least the section header + sub-heading + some body text
    this.ensureSpace(doc, data, 80);
    this.drawSectionHeader(doc, sectionLetter, 'Intelligence Analysis', bubbleIndex);

    if (data.trinityCheck.reasoning) {
      this.ensureSpace(doc, data, 30);

      doc
        .fillColor('#2D3748')
        .fontSize(9)
        .font('Helvetica')
        .text(data.trinityCheck.reasoning, 40, doc.y, { width: 515, align: 'justify', lineGap: 3 });
      doc.moveDown(2);
    }

    if (data.trinityCheck.reasoningInsights?.insights) {
      this.ensureSpace(doc, data, 30);
      doc
        .fillColor(this.primaryColor)
        .fontSize(9)
        .font('Helvetica-Bold')
        .text('KEY RECOMMENDATIONS', 40);
      doc.moveDown(0.5);

      const insights = data.trinityCheck.reasoningInsights.insights as string[];
      insights.forEach(insight => {
        // Each bullet: guard individually
        const lineH = doc.heightOfString(`- ${insight}`, { width: 485 }) + 4;
        this.ensureSpace(doc, data, lineH);
        doc
          .fillColor('#4A5568')
          .fontSize(9)
          .font('Helvetica')
          .text(`• ${insight}`, 45, doc.y, { width: 485 });
        doc.moveDown(0.3);
      });
    }
  }

  private generateFooter(doc: PDFKit.PDFDocument) {
    const pages = doc.bufferedPageRange();
    const totalPages = pages.count;

    const disclaimer =
      'DISCLAIMER: This report is generated by the True Claim Insight (TCI) Intelligence Engine using extracted document data and cross-verification algorithms. It is provided as a decision-support tool for loss adjusters and should be used in conjunction with professional judgment. TCI does not assume liability for decisions made based solely on this automated output.';
    const disclaimerBoxWidth = 515;
    const disclaimerTextWidth = disclaimerBoxWidth - 20;
    const leftMargin = 40;
    const boxPadding = 14; // inner vertical padding inside disclaimer box
    const gap = 8; // gap between disclaimer bottom and page-number
    const pageNumH = 18; // height budget for page-number line
    const bottomMargin = 24; // breathing room below page-number

    for (let i = 0; i < totalPages; i++) {
      doc.switchToPage(pages.start + i);
      doc.save();

      const pageH = doc.page.height;
      const pageW = doc.page.width;
      const origMarginBottom = doc.page.margins.bottom;
      const origMarginTop = doc.page.margins.top;

      doc.page.margins.bottom = 0;
      doc.page.margins.top = 0;
      doc.fontSize(6).font('Helvetica');
      const textH = doc.heightOfString(disclaimer, {
        width: disclaimerTextWidth,
        align: 'justify',
      });
      const disclaimerBoxH = textH + boxPadding;
      const pageNumY = pageH - bottomMargin - pageNumH;
      const disclaimerBoxY = pageNumY - gap - disclaimerBoxH;

      // Disclaimer box
      doc.rect(leftMargin, disclaimerBoxY, disclaimerBoxWidth, disclaimerBoxH).fill('#FFFFFF');
      doc
        .rect(leftMargin, disclaimerBoxY, disclaimerBoxWidth, disclaimerBoxH)
        .lineWidth(0.5)
        .stroke(this.borderColor);

      // Disclaimer text
      const textTopY = disclaimerBoxY + Math.floor(boxPadding / 2);
      doc.y = textTopY;
      doc
        .fillColor('#718096')
        .fontSize(6)
        .font('Helvetica')
        .text(disclaimer, leftMargin + 8, textTopY, {
          width: disclaimerTextWidth,
          align: 'justify',
          lineBreak: true,
          height: disclaimerBoxH - boxPadding + 2,
          ellipsis: false,
        });

      // Page number
      doc.y = pageNumY;
      doc
        .fontSize(6)
        .fillColor('#718096')
        .font('Helvetica')
        .text(`Page ${i + 1} of ${totalPages}`, leftMargin, pageNumY, {
          width: pageW - leftMargin * 2,
          align: 'right',
          lineBreak: false,
        });

      doc.page.margins.bottom = origMarginBottom;
      doc.page.margins.top = origMarginTop;
      doc.restore();
    }
  }
}
